# ── GOOGLE SHEETS ─────────────────────────────────────────────
@st.cache_data(ttl=300)
def load_all():
    creds = Credentials.from_service_account_info(
        dict(st.secrets["gcp_service_account"]),
        scopes=["https://spreadsheets.google.com/feeds",
                "https://www.googleapis.com/auth/drive"]
    )
    gc = gspread.authorize(creds)
    sh = gc.open(st.secrets["sheet_name"])

    # 1_Config
    cfg = {r[0]: r[1] for r in sh.worksheet("1_Config").get_all_values()[1:] if len(r) >= 2}

    # 2_MarketRates
    mr_raw = sh.worksheet("2_MarketRates").get_all_values()

    def ws_to_df(ws):
        rows = ws.get_all_values()
        if not rows or len(rows) < 2:
            return pd.DataFrame()
        # Find header row — first row with more than 1 non-empty cell
        header_idx = 0
        for i, row in enumerate(rows):
            non_empty = [c for c in row if str(c).strip()]
            if len(non_empty) > 1:
                header_idx = i
                break
        headers = rows[header_idx]
        data = rows[header_idx + 1:]
        seen = {}
        clean_headers = []
        for h in headers:
            h = str(h).strip()
            if not h:
                h = "_col"
            if h in seen:
                seen[h] += 1
                h = f"{h}_{seen[h]}"
            else:
                seen[h] = 0
            clean_headers.append(h)
        df = pd.DataFrame(data, columns=clean_headers)
        # Drop fully empty rows
        df = df[df.apply(lambda r: any(str(v).strip() for v in r), axis=1)]
        return df.reset_index(drop=True)

    # 5_Fixtures
    fx_df = ws_to_df(sh.worksheet("5_Fixtures"))

    # 6_RatesHistory
    r6_df = ws_to_df(sh.worksheet("6_RatesHistory"))

    # 7_BunkerHistory
    b7_df = ws_to_df(sh.worksheet("7_BunkerHistory"))

    return cfg, mr_raw, fx_df, r6_df, b7_df

# ── HELPERS ───────────────────────────────────────────────────
def var_html(v):
    v = str(v).strip()
    if v == "▲": return '<span class="var-up">▲</span>'
    if v == "▼": return '<span class="var-down">▼</span>'
    return '<span class="var-flat">—</span>'

def badge_html(val, cls):
    return f'<span class="badge {cls}">{val}</span>'

def parse_market_rates(raw):
    groups = {}
    current = None
    skip_next = False
    for row in raw[1:]:
        if not any(row): continue
        label = str(row[0]).strip()
        if label.startswith("Loading"):
            current = label
            groups[current] = []
            skip_next = True
        elif skip_next:
            skip_next = False
        elif current and label and label != "Discharge":
            if len(row) >= 5:
                groups[current].append({
                    "discharge": row[0], "c1": row[1],
                    "c2": row[2], "c3": row[3],
                    "var": row[4] if len(row) > 4 else "—"
                })
    return groups

def parse_bunker_history(b7_df):
    """7_BunkerHistory -> dict per fuel"""
    fuels = {}
    ports = [c for c in b7_df.columns if c not in ["Date","Fuel"]]
    for fuel in ["VLSFO","MGO","IFO 380"]:
        df = b7_df[b7_df["Fuel"] == fuel].copy()
        df["Date"] = pd.to_datetime(df["Date"], errors="coerce")
        for p in ports:
            df[p] = pd.to_numeric(df[p], errors="coerce")
        fuels[fuel] = df
    return fuels, ports

